// Outbox pattern — queue mutations for later sync
const useOfflineQueue = () => {
  const queueMutation = async (mutation) => {
    // Save to SQLite outbox table:
    await db.rawQuery(
      'INSERT INTO outbox (type, payload, created_at) VALUES (?, ?, ?)',
      [mutation.type, JSON.stringify(mutation.payload), Date.now()]
    );

    // Try to sync immediately if online:
    if (await NetInfo.fetch().then(s => s.isConnected)) {
      await flushQueue();
    }
  };

  const flushQueue = async () => {
    const pending = await db.rawQuery('SELECT * FROM outbox ORDER BY created_at');
    for (const item of pending._array) {
      try {
        await api.apply(JSON.parse(item.payload));
        await db.rawQuery('DELETE FROM outbox WHERE id = ?', [item.id]);
      } catch (err) {
        if (err.status === 409) { // Conflict
          await resolveConflict(item, err.serverState);
        }
        break; // Stop on error, retry next sync
      }
    }
  };

  return { queueMutation, flushQueue };
};

// Listen for network reconnection to flush queue:
useEffect(() => {
  const unsubscribe = NetInfo.addEventListener(state => {
    if (state.isConnected) flushQueue();
  });
  return unsubscribe;
}, []);

