  const { isConnected, isSlowConnection } = useNetworkState();

  if (!isConnected) return <OfflineBanner />;

  return (
    <FlatList
      // On slow connection: smaller page size, lower quality images
      pageSize={isSlowConnection ? 5 : 20}
    />
  );
}

// 1. TypeScript Spec (NativeBiometric.ts)
import type { TurboModule } from 'react-native';
import { TurboModuleRegistry } from 'react-native';

export interface Spec extends TurboModule {
  isAvailable(): boolean; // Synchronous!
  authenticate(reason: string): Promise<boolean>;
  getSupportedTypes(): string[]; // synchronous array return
}

export default TurboModuleRegistry.getEnforcing<Spec>('Biometric');

// 2. Android (BiometricModule.kt):
@ReactModule(name = BiometricModule.NAME)
class BiometricModule(context: ReactApplicationContext)
  : NativeBiometricSpec(context) {

  companion object { const val NAME = "Biometric" }

  override fun isAvailable(): Boolean {
    val bm = context.getSystemService(BiometricManager::class.java)
    return bm.canAuthenticate(BIOMETRIC_STRONG) == BIOMETRIC_SUCCESS
  }

  override fun authenticate(reason: String, promise: Promise) {
    val executor = ContextCompat.getMainExecutor(context)
    val prompt = BiometricPrompt(currentActivity!!, executor, object : AuthCallback() {
      override fun onAuthenticationSucceeded(result: AuthResult) {
        promise.resolve(true)
      }
      override fun onAuthenticationFailed() {
        promise.resolve(false)
      }
    })
    prompt.authenticate(PromptInfo.Builder().setTitle(reason).build())
  }
}

