// 2. Android (SignaturePadManager.kt):
@ReactModule(name = SignaturePadManager.NAME)
class SignaturePadManager : ViewGroupManager<SignaturePadView>() {
  override fun getName() = "SignaturePad"
  override fun createViewInstance(ctx: ThemedReactContext) = SignaturePadView(ctx)

  @ReactProp(name = "strokeColor")
  fun setStrokeColor(view: SignaturePadView, color: String?) {
    view.setStrokeColor(Color.parseColor(color ?: "#000000"))
  }

  @ReactProp(name = "strokeWidth", defaultFloat = 3f)
  fun setStrokeWidth(view: SignaturePadView, width: Float) {
    view.setStrokeWidth(width)
  }
}

