// Sentry React Native setup:
import * as Sentry from '@sentry/react-native';

Sentry.init({
  dsn: 'https://your-dsn@sentry.io/project-id',

  // Capture performance traces:
  tracesSampleRate: process.env.NODE_ENV === 'production' ? 0.1 : 1.0,

  // Link JS errors to native crashes:
  enableNative: true,

  // Track which OTA update version caused the crash:
  release: `${Application.nativeApplicationVersion}+${Updates.updateId}`,

  // Add navigation breadcrumbs automatically:
  integrations: [
    new Sentry.ReactNativeTracing({
      routingInstrumentation: new Sentry.ReactNavigationInstrumentation(),
    }),
  ],

  // Before send: strip sensitive data
  beforeSend(event) {
    // Remove auth tokens from breadcrumbs:
    event.breadcrumbs = event.breadcrumbs?.filter(
      b => !b.data?.url?.includes('/auth/')
    );
    return event;
  }
});

